  1→/**
  2→ * Agent Schema Validator CLI
  3→ *
  4→ * Scans all *.agent.yaml files in src/{core,modules/*}/agents/
  5→ * and validates them against the Zod schema.
  6→ *
  7→ * Usage: node tools/validate-agent-schema.js [project_root]
  8→ * Exit codes: 0 = success, 1 = validation failures
  9→ *
 10→ * Optional argument:
 11→ *   project_root - Directory to scan (defaults to BMAD repo root)
 12→ */
 13→
 14→const { glob } = require('glob');
 15→const yaml = require('yaml');
 16→const fs = require('node:fs');
 17→const path = require('node:path');
 18→const { validateAgentFile } = require('./schema/agent.js');
 19→
 20→/**
 21→ * Main validation routine
 22→ * @param {string} [customProjectRoot] - Optional project root to scan (for testing)
 23→ */
 24→async function main(customProjectRoot) {
 25→  console.log('🔍 Scanning for agent files...\n');
 26→
 27→  // Determine project root: use custom path if provided, otherwise default to repo root
 28→  const project_root = customProjectRoot || path.join(__dirname, '..');
 29→
 30→  // Find all agent files
 31→  const agentFiles = await glob('src/**/*.agent.yaml', {
 32→    cwd: project_root,
 33→    absolute: true,
 34→  });
 35→
 36→  if (agentFiles.length === 0) {
 37→    console.log('ℹ️  No agent files found. Skipping agent schema validation.');
 38→    console.log('   (Modules may optionally include agents in src/agents/)\n');
 39→    process.exit(0);
 40→  }
 41→
 42→  console.log(`Found ${agentFiles.length} agent file(s)\n`);
 43→
 44→  const errors = [];
 45→
 46→  // Validate each file
 47→  for (const filePath of agentFiles) {
 48→    const relativePath = path.relative(process.cwd(), filePath);
 49→
 50→    try {
 51→      const fileContent = fs.readFileSync(filePath, 'utf8');
 52→      const agentData = yaml.parse(fileContent);
 53→
 54→      // Convert absolute path to relative src/ path for module detection
 55→      const srcRelativePath = relativePath.startsWith('src/') ? relativePath : path.relative(project_root, filePath).replaceAll('\\', '/');
 56→
 57→      const result = validateAgentFile(srcRelativePath, agentData);
 58→
 59→      if (result.success) {
 60→        console.log(`✅ ${relativePath}`);
 61→      } else {
 62→        errors.push({
 63→          file: relativePath,
 64→          issues: result.error.issues,
 65→        });
 66→      }
 67→    } catch (error) {
 68→      errors.push({
 69→        file: relativePath,
 70→        issues: [
 71→          {
 72→            code: 'parse_error',
 73→            message: `Failed to parse YAML: ${error.message}`,
 74→            path: [],
 75→          },
 76→        ],
 77→      });
 78→    }
 79→  }
 80→
 81→  // Report errors
 82→  if (errors.length > 0) {
 83→    console.log('\n❌ Validation failed for the following files:\n');
 84→
 85→    for (const { file, issues } of errors) {
 86→      console.log(`\n📄 ${file}`);
 87→      for (const issue of issues) {
 88→        const pathString = issue.path.length > 0 ? issue.path.join('.') : '(root)';
 89→        console.log(`   Path: ${pathString}`);
 90→        console.log(`   Error: ${issue.message}`);
 91→        if (issue.code) {
 92→          console.log(`   Code: ${issue.code}`);
 93→        }
 94→      }
 95→    }
 96→
 97→    console.log(`\n\n💥 ${errors.length} file(s) failed validation`);
 98→    process.exit(1);
 99→  }
100→
101→  console.log(`\n✨ All ${agentFiles.length} agent file(s) passed validation!\n`);
102→  process.exit(0);
103→}
104→
105→// Run with optional command-line argument for project root
106→const customProjectRoot = process.argv[2];
107→main(customProjectRoot).catch((error) => {
108→  console.error('Fatal error:', error);
109→  process.exit(1);
110→});
