  1→/**
  2→ * Agent Schema Validation Test Runner
  3→ *
  4→ * Runs all test fixtures and verifies expected outcomes.
  5→ * Reports pass/fail for each test and overall coverage statistics.
  6→ *
  7→ * Usage: node test/test-agent-schema.js
  8→ * Exit codes: 0 = all tests pass, 1 = test failures
  9→ */
 10→
 11→const fs = require('node:fs');
 12→const path = require('node:path');
 13→const yaml = require('yaml');
 14→const { validateAgentFile } = require('./schema/agent.js');
 15→const { glob } = require('glob');
 16→
 17→// ANSI color codes
 18→const colors = {
 19→  reset: '\u001B[0m',
 20→  green: '\u001B[32m',
 21→  red: '\u001B[31m',
 22→  yellow: '\u001B[33m',
 23→  blue: '\u001B[34m',
 24→  cyan: '\u001B[36m',
 25→  dim: '\u001B[2m',
 26→};
 27→
 28→/**
 29→ * Parse test metadata from YAML comments
 30→ * @param {string} filePath
 31→ * @returns {{shouldPass: boolean, errorExpectation?: object, pathContext?: string}}
 32→ */
 33→function parseTestMetadata(filePath) {
 34→  const content = fs.readFileSync(filePath, 'utf8');
 35→  const lines = content.split('\n');
 36→
 37→  let shouldPass = true;
 38→  let pathContext = null;
 39→  const errorExpectation = {};
 40→
 41→  for (const line of lines) {
 42→    if (line.includes('Expected: PASS')) {
 43→      shouldPass = true;
 44→    } else if (line.includes('Expected: FAIL')) {
 45→      shouldPass = false;
 46→    }
 47→
 48→    // Parse error metadata
 49→    const codeMatch = line.match(/^# Error code: (.+)$/);
 50→    if (codeMatch) {
 51→      errorExpectation.code = codeMatch[1].trim();
 52→    }
 53→
 54→    const pathMatch = line.match(/^# Error path: (.+)$/);
 55→    if (pathMatch) {
 56→      errorExpectation.path = pathMatch[1].trim();
 57→    }
 58→
 59→    const messageMatch = line.match(/^# Error message: (.+)$/);
 60→    if (messageMatch) {
 61→      errorExpectation.message = messageMatch[1].trim();
 62→    }
 63→
 64→    const minimumMatch = line.match(/^# Error minimum: (\d+)$/);
 65→    if (minimumMatch) {
 66→      errorExpectation.minimum = parseInt(minimumMatch[1], 10);
 67→    }
 68→
 69→    const expectedMatch = line.match(/^# Error expected: (.+)$/);
 70→    if (expectedMatch) {
 71→      errorExpectation.expected = expectedMatch[1].trim();
 72→    }
 73→
 74→    const receivedMatch = line.match(/^# Error received: (.+)$/);
 75→    if (receivedMatch) {
 76→      errorExpectation.received = receivedMatch[1].trim();
 77→    }
 78→
 79→    const keysMatch = line.match(/^# Error keys: \[(.+)\]$/);
 80→    if (keysMatch) {
 81→      errorExpectation.keys = keysMatch[1].split(',').map((k) => k.trim().replaceAll(/['"]/g, ''));
 82→    }
 83→
 84→    const contextMatch = line.match(/^# Path context: (.+)$/);
 85→    if (contextMatch) {
 86→      pathContext = contextMatch[1].trim();
 87→    }
 88→  }
 89→
 90→  return {
 91→    shouldPass,
 92→    errorExpectation: Object.keys(errorExpectation).length > 0 ? errorExpectation : null,
 93→    pathContext,
 94→  };
 95→}
 96→
 97→/**
 98→ * Convert dot-notation path string to array (handles array indices)
 99→ * e.g., "agent.menu[0].trigger" => ["agent", "menu", 0, "trigger"]
100→ */
101→function parsePathString(pathString) {
102→  return pathString
103→    .replaceAll(/\[(\d+)\]/g, '.$1') // Convert [0] to .0
104→    .split('.')
105→    .map((part) => {
106→      const num = parseInt(part, 10);
107→      return isNaN(num) ? part : num;
108→    });
109→}
110→
111→/**
112→ * Validate error against expectations
113→ * @param {object} error - Zod error issue
114→ * @param {object} expectation - Expected error structure
115→ * @returns {{valid: boolean, reason?: string}}
116→ */
117→function validateError(error, expectation) {
118→  // Check error code
119→  if (expectation.code && error.code !== expectation.code) {
120→    return { valid: false, reason: `Expected code "${expectation.code}", got "${error.code}"` };
121→  }
122→
123→  // Check error path
124→  if (expectation.path) {
125→    const expectedPath = parsePathString(expectation.path);
126→    const actualPath = error.path;
127→
128→    if (JSON.stringify(expectedPath) !== JSON.stringify(actualPath)) {
129→      return {
130→        valid: false,
131→        reason: `Expected path ${JSON.stringify(expectedPath)}, got ${JSON.stringify(actualPath)}`,
132→      };
133→    }
134→  }
135→
136→  // For custom errors, strictly check message
137→  if (expectation.code === 'custom' && expectation.message && error.message !== expectation.message) {
138→    return {
139→      valid: false,
140→      reason: `Expected message "${expectation.message}", got "${error.message}"`,
141→    };
142→  }
143→
144→  // For Zod errors, check type-specific fields
145→  if (expectation.minimum !== undefined && error.minimum !== expectation.minimum) {
146→    return { valid: false, reason: `Expected minimum ${expectation.minimum}, got ${error.minimum}` };
147→  }
148→
149→  if (expectation.expected && error.expected !== expectation.expected) {
150→    return { valid: false, reason: `Expected type "${expectation.expected}", got "${error.expected}"` };
151→  }
152→
153→  if (expectation.received && error.received !== expectation.received) {
154→    return { valid: false, reason: `Expected received "${expectation.received}", got "${error.received}"` };
155→  }
156→
157→  if (expectation.keys) {
158→    const expectedKeys = expectation.keys.sort();
159→    const actualKeys = (error.keys || []).sort();
160→    if (JSON.stringify(expectedKeys) !== JSON.stringify(actualKeys)) {
161→      return {
162→        valid: false,
163→        reason: `Expected keys ${JSON.stringify(expectedKeys)}, got ${JSON.stringify(actualKeys)}`,
164→      };
165→    }
166→  }
167→
168→  return { valid: true };
169→}
170→
171→/**
172→ * Run a single test case
173→ * @param {string} filePath
174→ * @returns {{passed: boolean, message: string}}
175→ */
176→function runTest(filePath) {
177→  const metadata = parseTestMetadata(filePath);
178→  const { shouldPass, errorExpectation, pathContext } = metadata;
179→
180→  try {
181→    const fileContent = fs.readFileSync(filePath, 'utf8');
182→    let agentData;
183→
184→    try {
185→      agentData = yaml.parse(fileContent);
186→    } catch (parseError) {
187→      // YAML parse error
188→      if (shouldPass) {
189→        return {
190→          passed: false,
191→          message: `Expected PASS but got YAML parse error: ${parseError.message}`,
192→        };
193→      }
194→      return {
195→        passed: true,
196→        message: 'Got expected YAML parse error',
197→      };
198→    }
199→
200→    // Determine validation path
201→    // If pathContext is specified in comments, use it; otherwise derive from fixture location
202→    let validationPath = pathContext;
203→    if (!validationPath) {
204→      // Map fixture location to simulated src/ path
205→      const relativePath = path.relative(path.join(__dirname, 'fixtures/agent-schema'), filePath);
206→      const parts = relativePath.split(path.sep);
207→
208→      if (parts.includes('metadata') && parts[0] === 'valid') {
209→        // Valid metadata tests: check if filename suggests module or core
210→        const filename = path.basename(filePath);
211→        if (filename.includes('module')) {
212→          validationPath = 'src/modules/bmm/agents/test.agent.yaml';
213→        } else {
214→          validationPath = 'src/core/agents/test.agent.yaml';
215→        }
216→      } else if (parts.includes('metadata') && parts[0] === 'invalid') {
217→        // Invalid metadata tests: derive from filename
218→        const filename = path.basename(filePath);
219→        if (filename.includes('module') || filename.includes('wrong-module')) {
220→          validationPath = 'src/modules/bmm/agents/test.agent.yaml';
221→        } else if (filename.includes('core')) {
222→          validationPath = 'src/core/agents/test.agent.yaml';
223→        } else {
224→          validationPath = 'src/core/agents/test.agent.yaml';
225→        }
226→      } else {
227→        // Default to core agent path
228→        validationPath = 'src/core/agents/test.agent.yaml';
229→      }
230→    }
231→
232→    const result = validateAgentFile(validationPath, agentData);
233→
234→    if (result.success && shouldPass) {
235→      return {
236→        passed: true,
237→        message: 'Validation passed as expected',
238→      };
239→    }
240→
241→    if (!result.success && !shouldPass) {
242→      const actualError = result.error.issues[0];
243→
244→      // If we have error expectations, validate strictly
245→      if (errorExpectation) {
246→        const validation = validateError(actualError, errorExpectation);
247→
248→        if (!validation.valid) {
249→          return {
250→            passed: false,
251→            message: `Error validation failed: ${validation.reason}`,
252→          };
253→        }
254→
255→        return {
256→          passed: true,
257→          message: `Got expected error (${errorExpectation.code}): ${actualError.message}`,
258→        };
259→      }
260→
261→      // No specific expectations - just check that it failed
262→      return {
263→        passed: true,
264→        message: `Got expected validation error: ${actualError?.message}`,
265→      };
266→    }
267→
268→    if (result.success && !shouldPass) {
269→      return {
270→        passed: false,
271→        message: 'Expected validation to FAIL but it PASSED',
272→      };
273→    }
274→
275→    if (!result.success && shouldPass) {
276→      return {
277→        passed: false,
278→        message: `Expected validation to PASS but it FAILED: ${result.error.issues[0]?.message}`,
279→      };
280→    }
281→
282→    return {
283→      passed: false,
284→      message: 'Unexpected test state',
285→    };
286→  } catch (error) {
287→    return {
288→      passed: false,
289→      message: `Test execution error: ${error.message}`,
290→    };
291→  }
292→}
293→
294→/**
295→ * Main test runner
296→ */
297→async function main() {
298→  console.log(`${colors.cyan}╔═══════════════════════════════════════════════════════════╗${colors.reset}`);
299→  console.log(`${colors.cyan}║  Agent Schema Validation Test Suite                      ║${colors.reset}`);
300→  console.log(`${colors.cyan}╚═══════════════════════════════════════════════════════════╝${colors.reset}\n`);
301→
302→  // Find all test fixtures
303→  const testFiles = await glob('test/fixtures/agent-schema/**/*.agent.yaml', {
304→    cwd: path.join(__dirname, '..'),
305→    absolute: true,
306→  });
307→
308→  if (testFiles.length === 0) {
309→    console.log(`${colors.yellow}⚠️  No test fixtures found${colors.reset}`);
310→    process.exit(0);
311→  }
312→
313→  console.log(`Found ${colors.cyan}${testFiles.length}${colors.reset} test fixture(s)\n`);
314→
315→  // Group tests by category
316→  const categories = {};
317→  for (const testFile of testFiles) {
318→    const relativePath = path.relative(path.join(__dirname, 'fixtures/agent-schema'), testFile);
319→    const parts = relativePath.split(path.sep);
320→    const validInvalid = parts[0]; // 'valid' or 'invalid'
321→    const category = parts[1]; // 'top-level', 'metadata', etc.
322→
323→    const categoryKey = `${validInvalid}/${category}`;
324→    if (!categories[categoryKey]) {
325→      categories[categoryKey] = [];
326→    }
327→    categories[categoryKey].push(testFile);
328→  }
329→
330→  // Run tests by category
331→  let totalTests = 0;
332→  let passedTests = 0;
333→  const failures = [];
334→
335→  for (const [categoryKey, files] of Object.entries(categories).sort()) {
336→    const [validInvalid, category] = categoryKey.split('/');
337→    const categoryLabel = category.replaceAll('-', ' ').toUpperCase();
338→    const validLabel = validInvalid === 'valid' ? '✅' : '❌';
339→
340→    console.log(`${colors.blue}${validLabel} ${categoryLabel} (${validInvalid})${colors.reset}`);
341→
342→    for (const testFile of files) {
343→      totalTests++;
344→      const testName = path.basename(testFile, '.agent.yaml');
345→      const result = runTest(testFile);
346→
347→      if (result.passed) {
348→        passedTests++;
349→        console.log(`  ${colors.green}✓${colors.reset} ${testName} ${colors.dim}${result.message}${colors.reset}`);
350→      } else {
351→        console.log(`  ${colors.red}✗${colors.reset} ${testName} ${colors.red}${result.message}${colors.reset}`);
352→        failures.push({
353→          file: path.relative(process.cwd(), testFile),
354→          message: result.message,
355→        });
356→      }
357→    }
358→    console.log('');
359→  }
360→
361→  // Summary
362→  console.log(`${colors.cyan}═══════════════════════════════════════════════════════════${colors.reset}`);
363→  console.log(`${colors.cyan}Test Results:${colors.reset}`);
364→  console.log(`  Total:  ${totalTests}`);
365→  console.log(`  Passed: ${colors.green}${passedTests}${colors.reset}`);
366→  console.log(`  Failed: ${passedTests === totalTests ? colors.green : colors.red}${totalTests - passedTests}${colors.reset}`);
367→  console.log(`${colors.cyan}═══════════════════════════════════════════════════════════${colors.reset}\n`);
368→
369→  // Report failures
370→  if (failures.length > 0) {
371→    console.log(`${colors.red}❌ FAILED TESTS:${colors.reset}\n`);
372→    for (const failure of failures) {
373→      console.log(`${colors.red}✗${colors.reset} ${failure.file}`);
374→      console.log(`  ${failure.message}\n`);
375→    }
376→    process.exit(1);
377→  }
378→
379→  console.log(`${colors.green}✨ All tests passed!${colors.reset}\n`);
380→  process.exit(0);
381→}
382→
383→// Run
384→main().catch((error) => {
385→  console.error(`${colors.red}Fatal error:${colors.reset}`, error);
386→  process.exit(1);
387→});
