 56→ */
 57→function suppressConsole() {
 58→  const origLog = console.log;
 59→  const origStdoutWrite = process.stdout.write;
 60→  const origStderrWrite = process.stderr.write;
 61→  console.log = () => {};
 62→  process.stdout.write = () => true;
 63→  process.stderr.write = () => true;
 64→  return () => {
 65→    console.log = origLog;
 66→    process.stdout.write = origStdoutWrite;
 67→    process.stderr.write = origStderrWrite;
 68→  };
